effect.shader:
void main() {
    float segmentAngle = 360.0 / rcount;
    float rad = segmentAngle * 0.0174533;

    float offsetRad = offsetAngle * 0.0174533;

    vec2 origin = (centerPoint*vec2(1.0,-1.0))/1000.0 + 0.5;
    vec2 pos = acLayerNorm-origin;
    pos.x *= acLayerSize.x/acLayerSize.y;
    float r = length(pos);
    float a = atan(pos.y,pos.x);

    float sampleAngle = mod(a,rad);
    if( mirror ) {
        sampleAngle = abs(sampleAngle-rad/2.0);
    }
    sampleAngle += offsetRad;

    mat2 rmat = mat2(cos(sampleAngle),-sin(sampleAngle),sin(sampleAngle),cos(sampleAngle));

    vec2 sampleCoord = vec2(r,0.0) * rmat;

    sampleCoord.x /= acLayerSize.x/acLayerSize.y;

    sampleCoord += origin;

    sampleCoord = (vec4(sampleCoord,0.0,1.0) * acLayerToScreen).xy;

    gl_FragColor = texture2DCv(inputImg.texture,sampleCoord);
}
